import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface RecipeData {
  recipe: {
    title: string;
    ingredientsCount: number;
    cookingTime: string;
    nutrition: {
      calories: number;
      protein: string;
      carbs: string;
      fat: string;
    };
  };
}

interface MetaData {
  theme: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const recipeData = response.data as RecipeData;
  const metaData = response.meta as MetaData;
  const { recipe } = recipeData;
  const { primaryColor, accentColor } = metaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              {recipe.title}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              {recipe.ingredientsCount} ingredients • {recipe.cookingTime}
            </Typography>
          </Box>
          <Stack direction="row" spacing={1}>
            <Chip label={`Calories: ${recipe.nutrition.calories}`} sx={{ bgcolor: accentColor, color: '#FFFFFF', fontSize: '11px' }} />
            <Chip label={`Protein: ${recipe.nutrition.protein}`} sx={{ bgcolor: accentColor, color: '#FFFFFF', fontSize: '11px' }} />
            <Chip label={`Carbs: ${recipe.nutrition.carbs}`} sx={{ bgcolor: accentColor, color: '#FFFFFF', fontSize: '11px' }} />
            <Chip label={`Fat: ${recipe.nutrition.fat}`} sx={{ bgcolor: accentColor, color: '#FFFFFF', fontSize: '11px' }} />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
